// Webhook body carries { founder_id }. application_id is deliberately NOT an input --
// design.md SS4/SS9: 03 scores the PERSON, not an application.
const item = $input.first().json;
const body = item.body || {};
const founder_id = body.founder_id || item.founder_id;
if (!founder_id) throw new Error('f03-score-founder: founder_id is required');
return [{ json: { founder_id } }];

// Called by 02 (radar) / 08 (intake) as a sub-workflow with { founder_id }.
const item = $input.first().json || {};
const founder_id = item.founder_id;
if (!founder_id) throw new Error('f03-score-founder: founder_id is required');
return [{ json: { founder_id } }];

// One UUID per run of f03-score-founder (design.md SS4.9) -- echoed into every
// ai_runs.output_json below so the four ledger rows join to the components.
// require('crypto') is allow-listed in infra/n8n/docker-compose.yml
// (NODE_FUNCTION_ALLOW_BUILTIN=crypto,url), shared with feature 04.
const { randomUUID } = require('crypto');
const inp = $input.first().json;
return [{ json: { founder_id: inp.founder_id, run_id: randomUUID() } }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, ''), KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function pgGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET', url: SB + '/rest/v1/' + path,
    headers: { apikey: KEY, Authorization: 'Bearer ' + KEY }, json: true,
  });
}
const inp = $input.first().json;
const founders = await pgGet.call(this,
  'founders?id=eq.' + inp.founder_id + '&select=id,full_name,headline,location_country');
const founder = founders[0] || { id: inp.founder_id, full_name: null, headline: null, location_country: null };

// founder_company.is_current is the mechanism (design.md 01 SS5.3) by which the score
// follows a person across companies -- 'current company' means is_current=true.
const fc = await pgGet.call(this,
  'founder_company?founder_id=eq.' + inp.founder_id +
  '&is_current=eq.true&select=companies(name,one_liner,category,stage)&limit=1');
const company = (fc[0] && fc[0].companies) ||
  { name: null, one_liner: null, category: null, stage: null };

return [{ json: { ...inp, founder, company } }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, ''), KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function pgGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET', url: SB + '/rest/v1/' + path,
    headers: { apikey: KEY, Authorization: 'Bearer ' + KEY }, json: true,
  });
}
const inp = $input.first().json;
// design.md SS4.1: claims JOIN cards (WHERE cards.founder_id = $1) LEFT JOIN evidence
// LEFT JOIN raw_signals. PostgREST resource embedding does this in one request:
//  - cards!inner(founder_id) + cards.founder_id=eq.<id> filters through the join
//    (the '!inner' hint is required for PostgREST to let a top-level filter reference
//    an embedded resource).
//  - evidence(...) embeds the one-to-many child rows as an array per claim -- "a claim
//    may have MULTIPLE evidence rows" (task brief) falls out of this for free.
//  - raw_signals(source) is nested INSIDE each evidence row via evidence.raw_signal_id;
//    PostgREST returns `raw_signals: null` when that FK is null (verified live against
//    the fixture DB before wiring this in), giving the required
//    "evidence.source must be the JOINED raw_signals.source, null when raw_signal_id is
//    null" without a second round trip.
const select = 'id,topic,text_verbatim,source_kind,created_at,cards!inner(founder_id),' +
  'evidence(id,tier,quote_verbatim,source_url,raw_signal_id,raw_signals(source))';
const claims = await pgGet.call(this,
  'claims?select=' + select + '&cards.founder_id=eq.' + inp.founder_id);
return [{ json: { ...inp, claims } }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, ''), KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function pgGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET', url: SB + '/rest/v1/' + path,
    headers: { apikey: KEY, Authorization: 'Bearer ' + KEY }, json: true,
  });
}
const inp = $input.first().json;
const rows = await pgGet.call(this,
  'score_formulas?axis=eq.founder_score&active=eq.true&select=version,config&limit=1');
if (!rows || !rows.length) {
  throw new Error('f03-score-founder: no active score_formulas row for axis=founder_score');
}
// scoring.js's trend guard (SS4.5) compares config.version against the previous scores
// row's formula_version -- but `version` lives OUTSIDE `config` in score_formulas
// (schema.sql). Fold it into the config object here, once, for every downstream reader
// (GATE, AGGREGATE, the scores-row write, the output contract) to share.
const formula_config = { ...rows[0].config, version: rows[0].version };
return [{ json: { ...inp, formula_config } }];

// design.md SS4.7: route each claim by claims.topic PREFIX into its sub-scorer's pack;
// red-flags always gets the union of every claim (cross-cutting visibility to spot
// contradictions). A claim matching no prefix is never dropped -- plan.md task C1:
// "unmatched topic -> union pack (never dropped)" -- broadcast into EVERY positive
// sub-scorer's pack (not just red-flags), because a claim silently invisible to every
// scored criterion is exactly the starvation SS4.7 warns against; red-flags already sees
// it unconditionally either way.
const TIER_RANK = { documented: 3, discovered: 2, inferred: 1, missing: 0 };
function bestTierRank(claim) {
  var best = -1;
  (claim.evidence || []).forEach(function (e) {
    var r = TIER_RANK.hasOwnProperty(e.tier) ? TIER_RANK[e.tier] : -1;
    if (r > best) best = r;
  });
  return best;
}

const inp = $input.first().json;
const cfg = inp.formula_config || {};
const routing = cfg.topic_routing || {};
const prefixMap = routing.prefix_map || {};
const cap = cfg.max_claims_per_agent || 40;

// Normalize into gate.js's contextPacks claim shape, pre-joining raw_signals.source onto
// each evidence entry (design SS4.1 -- "PRE-JOINED by the caller -- gate.js does no DB
// access", per lib/f03/gate.js's own header contract).
const normClaims = (inp.claims || []).map(function (c) {
  return {
    claim_id: c.id,
    text_verbatim: c.text_verbatim,
    topic: c.topic,
    source_kind: c.source_kind,
    created_at: c.created_at,
    evidence: (c.evidence || []).map(function (e) {
      return {
        tier: e.tier,
        quote_verbatim: e.quote_verbatim,
        source_url: e.source_url,
        raw_signal_id: e.raw_signal_id || null,
        source: (e.raw_signals && e.raw_signals.source) || null,
      };
    }),
  };
});

const positiveNames = ['execution-signals', 'expertise-signals', 'leadership-sales-proxies'];
const buckets = { 'execution-signals': [], 'expertise-signals': [], 'leadership-sales-proxies': [] };
const unmatched = [];
normClaims.forEach(function (c) {
  var routed = null;
  Object.keys(prefixMap).some(function (prefix) {
    if (c.topic && c.topic.indexOf(prefix) === 0) { routed = prefixMap[prefix]; return true; }
    return false;
  });
  if (routed && buckets[routed]) buckets[routed].push(c);
  else unmatched.push(c);
});

// Cap: max_claims_per_agent, ordered by evidence.tier (documented -> discovered ->
// inferred) then claims.created_at desc (design SS4.7).
function sortAndCap(list) {
  var sorted = list.slice().sort(function (a, b) {
    var rb = bestTierRank(b) - bestTierRank(a);
    if (rb !== 0) return rb;
    return new Date(b.created_at) - new Date(a.created_at);
  });
  return sorted.slice(0, cap);
}

const packs = {};
positiveNames.forEach(function (name) {
  var combined = sortAndCap(buckets[name].concat(unmatched));
  packs[name] = { claim_ids: combined.map(function (c) { return c.claim_id; }), claims: combined };
});
var redFlagCombined = sortAndCap(normClaims); // union of ALL claims, uncapped concern removed by cap
packs['red-flags'] = {
  claim_ids: redFlagCombined.map(function (c) { return c.claim_id; }),
  claims: redFlagCombined,
};

return [{ json: { ...inp, packs } }];

// Fed by the Merge node above (mode: append, numberInputs: 4), which concatenates the
// 4 sub-scorer items into one list ONLY once all 4 parallel LLM branches have completed
// -- $input.all() here returns exactly 4 items, one per sub-scorer, all sharing the same
// upstream context (packs, founder_id, run_id, formula_config, ...) since they all
// descend from "Build 4 routed context packs". Merge each item's one-key agent_output
// into one map.
const items = $input.all();
const base = { ...items[0].json };
delete base.agent_output;
const rawAgentOutputs = {};
items.forEach(function (it) { Object.assign(rawAgentOutputs, it.json.agent_output || {}); });
return [{ json: { ...base, rawAgentOutputs } }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, ''), KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function pg(method, path, body, prefer) {
  const headers = { apikey: KEY, Authorization: 'Bearer ' + KEY, 'Content-Type': 'application/json' };
  if (prefer) headers.Prefer = prefer;
  return await this.helpers.httpRequest({ method, url: SB + '/rest/v1/' + path, headers, body, json: true });
}
const inp = $input.first().json;
// design.md I8 / SS4.3: every AI call is ledgered ALWAYS, BEFORE validation -- write all
// 4 rows unconditionally, whatever GATE later does with the content. run_id is echoed
// into each output_json so the 4 ledger rows join to the score_components they produced
// (design SS4.9: deliberately not ai_runs.n8n_execution_id, which is text and scoped to
// a single node).
const subscorers = ['execution-signals', 'expertise-signals', 'leadership-sales-proxies', 'red-flags'];
const ai_run_ids = {};
for (const name of subscorers) {
  const out = (inp.rawAgentOutputs && inp.rawAgentOutputs[name]) || { error: 'no output received' };
  const output_json = { ...out, run_id: inp.run_id };
  const rows = await pg.call(this, 'POST', 'ai_runs', {
    task_type: 'scoring',
    founder_id: inp.founder_id,
    model: "gpt-5.6-luna",
    prompt_version: "p1-2026.07",
    output_json,
    n8n_execution_id: String($execution.id),
  }, 'return=representation');
  ai_run_ids[name] = rows[0].id;
}
return [{ json: { ...inp, ai_run_ids } }];

